    if event.variant == InputVariant::Move {
        self.update_hover(event.mouse_x, event.mouse_y);
        return false;
    }
    match event.key {
        InputKey::MouseLeft => match event.variant {
            InputVariant::Press => {
                self.pressed = true;
                if let Some(cb) = &mut self.on_press_state {
                    cb(true);
